# Planify | Etapa 10.0 Studio | Aplicador blindado
# Este script evita here-strings grandes para nao quebrar no Windows PowerShell.
# Ele aplica a etapa, roda build, cria commit e faz push se o build passar.

$ErrorActionPreference = "Stop"

$root = (Get-Location).Path
$packagePath = Join-Path $root "package.json"

if (!(Test-Path $packagePath)) {
  throw "Execute este script dentro da raiz do projeto Planify. Exemplo: cd C:\planify"
}

$stamp = Get-Date -Format "yyyy-MM-dd-HH-mm-ss"
$backupDir = Join-Path $root "backups\etapa-10-0-studio-blindada-$stamp"

function Ensure-Dir {
  param([string]$Path)
  if (!(Test-Path $Path)) {
    New-Item -ItemType Directory -Path $Path -Force | Out-Null
  }
}

function Backup-File {
  param([string]$RelativePath)
  $full = Join-Path $root $RelativePath
  if (Test-Path $full) {
    $dest = Join-Path $backupDir $RelativePath
    $destDir = Split-Path $dest -Parent
    Ensure-Dir $destDir
    Copy-Item $full $dest -Force
  }
}

function Write-B64File {
  param(
    [string]$RelativePath,
    [string]$Base64Content
  )

  $full = Join-Path $root $RelativePath
  $dir = Split-Path $full -Parent
  Ensure-Dir $dir
  Backup-File $RelativePath

  $bytes = [Convert]::FromBase64String($Base64Content)
  [System.IO.File]::WriteAllBytes($full, $bytes)

  Write-Host "OK: $RelativePath" -ForegroundColor Green
}

Ensure-Dir $backupDir

Write-Host ""
Write-Host "=== Planify | Etapa 10.0 Studio blindada ===" -ForegroundColor Cyan
Write-Host "Backup: $backupDir" -ForegroundColor DarkCyan
Write-Host ""

${b64_0} = (
  '' +
  '' +
  '' +
  '' 
)
Write-B64File "src\lib\studio\planifyStudioConfig.ts" ${b64_0}

${b64_1} = (
  '' +
  '' +
  '' +
  '' +
  '' 
)
Write-B64File "src\components\studio\PlanifyStudioShell.tsx" ${b64_1}

${b64_2} = (
  '' +
  '' +
  '' +
  'Cn0=' 
)
Write-B64File "src\app\page.tsx" ${b64_2}

${b64_3} = (
  'aW1wb3J0IFBsYW5pZnlTdHVkaW9TaGVsbCBmcm9tICJAL2NvbXBvbmVudHMvc3R1ZGlvL1BsYW5pZnlTdHVkaW9TaGVsbCI7CgpleHBvcnQgZGVmYXVsdCBmdW5jdGlvbiBEYXNoYm9hcmRQYWdlKCkgewogIHJldHVybiA8UGxhbmlmeVN0dWRpb1NoZWxsIC8+Owp9' 
)
Write-B64File "src\app\dashboard\page.tsx" ${b64_3}

${b64_4} = (
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' +
  '' 
)
Write-B64File "src\app\materiais\page.tsx" ${b64_4}

${b64_5} = (
  '' +
  '' +
  '' +
  '' +
  '' 
)
Write-B64File "src\app\api\materiais\gerar\route.ts" ${b64_5}


Write-Host ""
Write-Host "=== Build de producao ===" -ForegroundColor Cyan
npm run build

if ($LASTEXITCODE -ne 0) {
  throw "Build falhou. Commit e push cancelados para proteger a Vercel."
}

Write-Host ""
Write-Host "=== Git status ===" -ForegroundColor Cyan
git status --short

git add -- `
src/app/page.tsx `
src/app/dashboard/page.tsx `
src/app/materiais/page.tsx `
src/app/api/materiais/gerar/route.ts `
src/components/studio/PlanifyStudioShell.tsx `
src/lib/studio/planifyStudioConfig.ts `
scripts/planify-etapa-10-0-studio-blindado.ps1

$changes = git diff --cached --name-only

if (-not $changes) {
  Write-Host "Nenhuma alteracao nova para commit." -ForegroundColor Yellow
} else {
  $commitMessage = "feat: aplicar Planify Studio etapa 10.0"
  git commit -m $commitMessage
}

$branch = git branch --show-current

if (-not $branch) {
  throw "Nao consegui identificar a branch atual."
}

Write-Host ""
Write-Host "=== Push para origin/$branch ===" -ForegroundColor Cyan
git push origin $branch

Write-Host ""
Write-Host "=== Concluido ===" -ForegroundColor Green
Write-Host "Build aprovado. Commit/push finalizado. A Vercel deve iniciar o deploy automaticamente se a branch estiver conectada." -ForegroundColor Green
